def social_clusters(n, scores, operations):
    parent = list(range(n))
    rank = [0] * n
    size = [1] * n
    spokesperson = list(range(n))

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(x, y):
        rx, ry = find(x), find(y)
        if rx == ry:
            return
        if rank[rx] < rank[ry]:
            rx, ry = ry, rx
        parent[ry] = rx
        size[rx] += size[ry]
        if rank[rx] == rank[ry]:
            rank[rx] += 1
        sx, sy = spokesperson[rx], spokesperson[ry]
        if scores[sy] > scores[sx] or (scores[sy] == scores[sx] and sy < sx):
            spokesperson[rx] = sy

    results = []
    for op in operations:
        if op[0] == "friend":
            _, u, v = op
            union(u, v)
        elif op[0] == "spokesperson":
            _, u = op
            root = find(u)
            results.append(spokesperson[root])
        elif op[0] == "size":
            _, u = op
            root = find(u)
            results.append(size[root])
    return results
